class AnswerWithReasoning(dspy.Signature):
    """Answer a factual question. Think step by step before giving the final answer."""
    question: str = dspy.InputField()
    reasoning: str = dspy.OutputField(desc="Step-by-step reasoning process")
    answer: str = dspy.OutputField(desc="The concise final answer")

class ReasoningQA(dspy.Module):
    def __init__(self):
        super().__init__()
        # ChainOfThought automatically adds a "reasoning" field before the answer.
        self.answer_q = dspy.ChainOfThought(AnswerWithReasoning)

    def forward(self, question: str) -> dspy.Prediction:
        return self.answer_q(question=question)

qa = ReasoningQA()
result = qa(question="What is the capital of the country whose flag has three equal vertical bands of blue, white, and red from left to right?")
print(result.reasoning)
print(result.answer)
